import { FileMap, FileMetadata } from '../types';

export class FileSystem {
  private files: FileMap = {};
  private metadata: FileMetadata = {};
  private readonly STORAGE_KEY_FILES = 'aimud_files';
  private readonly STORAGE_KEY_META = 'aimud_metadata';

  constructor() {
    this.loadFromStorage();
  }

  private loadFromStorage() {
    try {
      const stored = localStorage.getItem(this.STORAGE_KEY_FILES);
      if (stored) {
        this.files = JSON.parse(stored);
      }
      const storedMeta = localStorage.getItem(this.STORAGE_KEY_META);
      if (storedMeta) {
        this.metadata = JSON.parse(storedMeta);
      }
    } catch (e) {
      console.error('Failed to load files:', e);
    }
  }

  private saveToStorage() {
    try {
      localStorage.setItem(this.STORAGE_KEY_FILES, JSON.stringify(this.files));
      localStorage.setItem(this.STORAGE_KEY_META, JSON.stringify(this.metadata));
    } catch (e) {
      console.error('Failed to save files:', e);
    }
  }

  write(filename: string, content: string, displayName: string | null = null) {
    this.files[filename] = content;
    if (displayName) {
      this.metadata[filename] = { displayName };
    } else if (!this.metadata[filename]) {
      this.metadata[filename] = { displayName: this.generateDisplayName(filename) };
    }
    this.saveToStorage();
  }

  private generateDisplayName(filename: string): string {
    let name = filename.replace(/\.txt$/, '');
    name = name.replace(/_/g, ' ');
    name = name.replace(/\s+\d+$/, '');
    return name;
  }

  getDisplayName(filename: string): string {
    return this.metadata[filename]?.displayName || this.generateDisplayName(filename);
  }

  read(filename: string): string | null {
    return this.files[filename] || null;
  }

  exists(filename: string): boolean {
    return Object.prototype.hasOwnProperty.call(this.files, filename);
  }

  delete(filename: string) {
    delete this.files[filename];
    delete this.metadata[filename];
    this.saveToStorage();
  }

  list(): string[] {
    return Object.keys(this.files).sort();
  }

  getAll(): FileMap {
    return { ...this.files };
  }

  clear() {
    this.files = {};
    this.metadata = {};
    localStorage.removeItem(this.STORAGE_KEY_FILES);
    localStorage.removeItem(this.STORAGE_KEY_META);
  }

  findFileByReference(ref: string): string | null {
    if (this.exists(ref)) return ref;
    if (this.exists(ref + '.txt')) return ref + '.txt';

    // Try to find by display name
    for (const [filename, meta] of Object.entries(this.metadata)) {
      if (meta.displayName === ref) return filename;
    }

    // Try partial match
    const refLower = ref.toLowerCase();
    for (const filename of Object.keys(this.files)) {
      if (filename.toLowerCase().includes(refLower)) return filename;
    }

    return null;
  }
}

import { GoogleGenAI } from "@google/genai";
import { FileSystem } from "./fileSystem";
import { AIResponse, CheckDef } from "../types";

const SYSTEM_PROMPT = `You are the backend engine for an AI-MUD system. Your role is to:

1. Create and manage text files as the source of truth
2. Generate world content on-demand based on player perception
3. Verify actions against World Rules and Player stats
4. Calculate time costs and update global time
5. Manage status effects with expiration timestamps
6. Track unique object instances
7. Use hide[...] syntax for information not yet revealed to player
8. Update files dynamically and accurately
9. NEVER forget to create/update files for NPCs, items, locations, or any entities that appear

CRITICAL FILE MANAGEMENT RULES:
- Create a "Guide.txt" file that references these instructions and acts as the internal operating manual
- Create "WorldRules.txt" defining physics, magic, tech, logic, time costs, and encumbrance effects
- Create "Player.txt" with DYNAMIC attributes specific to the character (health, energy, body parts relevant to their form, inventory, knowledge, etc.)
  * For a dog: nose sensitivity, tail status, paw health, etc.
  * For a human: hands, legs, stamina, etc.
  * For a robot: battery, circuits, sensors, etc.
  * NEVER use generic attributes that don't match the entity's nature
- Create "WorldTime.txt" with ACTUAL date/time/year appropriate for the world setting
  * Future setting: year 2076+
  * WW2 setting: 1940s
  * Medieval: appropriate historical year
  * Format: "HH:MM:SS AM/PM - Mon DD, YYYY"
- Create files for EVERY entity that appears: NPCs (including background NPCs like guards, townsfolk, crowds), items, locations
  * "KingsGuard_1.txt" gets displayName: "King's Guard"
  * "TownsPerson_5.txt" gets displayName: "John" (or their actual name)
- Use hide[...] for secrets/traps/hidden info in files - this content is completely hidden from player view
- Track unique instances: [ObjectType_ID(status)]
- Status effects: [Status:Type_ID(Expires: TIME)]
- Apply encumbrance effects realistically when inventory weight matters

FILE REFERENCE SYNTAX:
Use [DisplayName] or [FileName] in narrative text - these become clickable links to files
Examples: [Player], [King's Guard], [Iron Sword], [Old Church]

TIME SYSTEM:
- WorldTime.txt contains the CURRENT time/date/year, not elapsed time
- Calculate action duration and ADD to current time
- Update WorldTime.txt with new current time after each action
- Check and expire status effects against current time

UPDATE VALUES:
- Health changes: negative for damage, positive for healing
- Energy: negative when spent, positive for restored
- Time: always show the time cost in seconds (e.g., "+30s" for 30 second action)
- Inventory: "+1" when adding, "-1" when removing

CRITICAL: Before EVERY action, check:
1. Does this entity have a file? If not, CREATE it immediately
2. Is the Player.txt accurate for this specific character type?
3. Are status effects expired based on current WorldTime?
4. Does this action respect WorldRules physics/magic/tech?
5. Does player have required stats/items/energy?

RESPONSE FORMAT:
Respond with JSON only:
{
  "narrative": "Story text with [DisplayName] references for all entities/items/locations",
  "updates": [
    {"type": "stat", "text": "Health -10", "value": -10},
    {"type": "item", "text": "Added Iron Key", "value": 1},
    {"type": "time", "text": "+30s", "value": 30}
  ],
  "files": {
    "filename.txt": {"content": "file content with hide[secrets]", "displayName": "Display Name"}
  },
  "gameOver": false,
  "checks": [] 
}

If probability checks are required, return empty narrative and fill the "checks" array.
Set gameOver to true ONLY when player health/critical stat reaches 0.
For starting prompt, create initial world files with appropriate time/year and set the scene.`;

export class AIEngine {
  private fs: FileSystem;
  private ai: GoogleGenAI;

  constructor(fileSystem: FileSystem) {
    this.fs = fileSystem;
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async initialize(startingPrompt: string): Promise<AIResponse | null> {
    try {
      const prompt = `Initialize world: ${startingPrompt}`;
      return await this.handleRequest(prompt);
    } catch (e) {
      console.error("Initialization failed", e);
      return { narrative: "System initialization failed. Please check API Key." };
    }
  }

  async processAction(action: string): Promise<AIResponse | null> {
    try {
      const files = this.fs.getAll();
      const context = Object.entries(files)
        .map(([name, content]) => `=== ${name} ===\n${content}`)
        .join('\n\n');

      const prompt = `Current files:\n${context}\n\nPlayer action: ${action}\n\nProcess this action. If it requires rolls (probability/skill/luck), return "checks". If not, return "narrative" and updates.`;

      return await this.handleRequest(prompt);
    } catch (e) {
      console.error("Processing failed", e);
      return { narrative: "Error processing action." };
    }
  }

  private async handleRequest(userPrompt: string): Promise<AIResponse | null> {
    // Phase 1: Analyze/Execute
    let responseText = await this.callAI(userPrompt);
    let data: AIResponse;

    try {
      data = JSON.parse(responseText);
    } catch (e) {
      console.error("JSON Parse Error", e, responseText);
      // Attempt to clean markdown json blocks if present
      const match = responseText.match(/```json([\s\S]*?)```/);
      if (match) {
        try {
          data = JSON.parse(match[1]);
        } catch (e2) {
           return { narrative: "System Error: AI returned invalid JSON." };
        }
      } else {
        return { narrative: "System Error: AI returned invalid format." };
      }
    }

    // Phase 2: If checks are required
    if (data.checks && Array.isArray(data.checks) && data.checks.length > 0) {
      const results = data.checks.map(check => {
        const roll = Math.floor(Math.random() * 1001);
        const outcome = this.determineOutcome(roll, check.thresholds);
        return {
          name: check.name,
          description: check.description,
          outcome: outcome,
          roll: roll,
          thresholds: check.thresholds
        };
      });

      const resultReport = results.map(r => 
        `Check: ${r.name}\nReason: ${r.description}\nRoll: ${r.roll} / 1000\nThresholds: ${JSON.stringify(r.thresholds)}\nRESULT: ${r.outcome}`
      ).join('\n\n');

      const followUpPrompt = `PREVIOUS CONTEXT: ${userPrompt}\n\n[SYSTEM: Probability Checks Completed]\n\n${resultReport}\n\nBased on these FAIR and FINAL results, generate the narrative and file updates. Include the Check Name and Result (e.g. "[Jump: Failure]") in the narrative, but do NOT state the raw roll numbers.`;

      // We make a fresh call with the context combined, as we don't maintain a full chat history object here 
      // (The FS is the history source of truth).
      responseText = await this.callAI(followUpPrompt);
      try {
        const match = responseText.match(/```json([\s\S]*?)```/);
        data = match ? JSON.parse(match[1]) : JSON.parse(responseText);
      } catch (e) {
        console.error("JSON Parse Error Phase 2", e);
        return { narrative: "Error processing check results." };
      }
    }

    this.processResponseData(data);
    return data;
  }

  private determineOutcome(roll: number, thresholds: { [outcome: string]: number }): string {
    const sorted = Object.entries(thresholds)
      .sort(([, valA], [, valB]) => valB - valA);

    for (const [outcome, minVal] of sorted) {
      if (roll >= minVal) return outcome;
    }
    return "Failure";
  }

  private processResponseData(data: AIResponse) {
    if (!data) return;

    if (data.files) {
      for (const [filename, fileData] of Object.entries(data.files)) {
        if (typeof fileData === 'string') {
          this.fs.write(filename, fileData);
        } else if (fileData && fileData.content) {
          this.fs.write(filename, fileData.content, fileData.displayName);
        }
      }
    }
  }

  private async callAI(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: SYSTEM_PROMPT,
          responseMimeType: 'application/json',
          temperature: 0.7,
        }
      });

      return response.text || "{}";
    } catch (e) {
      console.error("Gemini API Call Failed", e);
      throw e;
    }
  }
}

import React, { useEffect, useRef } from 'react';
import { NarrativeEntry, FileSystem } from '../types';

interface NarrativeWindowProps {
  history: NarrativeEntry[];
  fileSystem: FileSystem; // Passed not for reading, but for resolving references if needed
  onReferenceClick: (ref: string) => void;
  debugMode: boolean;
}

const NarrativeWindow: React.FC<NarrativeWindowProps> = ({ history, onReferenceClick, debugMode }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  // Helper to parse text with [Links] and hide[...]
  const parseText = (text: string) => {
    // 1. Handle hide[...]
    let processed = text;
    if (debugMode) {
      processed = processed.replace(/hide\[(.*?)\]/gs, (match, p1) => `<span class="bg-yellow-900/30 text-yellow-300 px-1 rounded border border-yellow-700/50 border-dashed">${p1}</span>`);
    } else {
      processed = processed.replace(/hide\[.*?\]/gs, '<span class="text-gray-600 italic font-mono">[hidden]</span>');
    }

    // 2. Handle [Object] links
    // We split by the regex and map to React elements to avoid dangerouslySetInnerHTML for the whole thing where possible,
    // but mixing regexes is tricky. For a terminal app, dangerous HTML with strict regex control is often cleaner for "rich text".
    processed = processed.replace(/\[([^\]]+)\]/g, (match, ref) => {
       return `<span class="text-yellow-400 hover:text-yellow-200 hover:underline cursor-pointer" data-ref="${ref}">${ref}</span>`;
    });

    return processed;
  };

  const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const target = e.target as HTMLElement;
    if (target.dataset.ref) {
      onReferenceClick(target.dataset.ref);
    }
  };

  return (
    <div className="flex-1 overflow-y-auto p-4 space-y-4 font-mono bg-black" onClick={handleClick}>
      {history.length === 0 && (
        <div className="text-green-500 italic">
          Initializing system connection...
        </div>
      )}

      {history.map((entry) => (
        <div key={entry.id} className={`narrative-entry leading-relaxed ${
          entry.type === 'user' ? 'text-blue-400 font-bold border-l-2 border-blue-900 pl-2' : 
          entry.type === 'system' ? 'text-green-500 italic' : 
          'text-gray-300'
        }`}>
          {entry.type === 'user' && <span className="mr-2">&gt;</span>}
          <span dangerouslySetInnerHTML={{ __html: parseText(entry.text) }} />
        </div>
      ))}
      <div ref={bottomRef} />
    </div>
  );
};

export default NarrativeWindow;

import React, { useState } from 'react';
import { FileSystem, UpdateItem } from '../types';
import { FileText, ChevronRight, ChevronDown, Activity, Settings, RefreshCw } from 'lucide-react';

interface SidebarProps {
  files: string[];
  fileSystem: FileSystem;
  updates: UpdateItem[];
  debugMode: boolean;
  onToggleDebug: () => void;
  onReset: () => void;
  expandedFile: string | null;
  setExpandedFile: (filename: string | null) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  files, 
  fileSystem, 
  updates, 
  debugMode, 
  onToggleDebug, 
  onReset,
  expandedFile,
  setExpandedFile
}) => {

  const formatContent = (content: string) => {
    if (!content) return '';
    if (debugMode) {
      return content.replace(/hide\[(.*?)\]/gs, '<span class="text-yellow-300 bg-yellow-900/20 px-1 border border-dashed border-yellow-800 rounded">$1</span>');
    }
    return content.replace(/hide\[.*?\]/gs, '<span class="text-gray-600 italic font-mono">[hidden]</span>');
  };

  const parseLinks = (html: string) => {
      // Very basic link highligting within file view, not interactive in sidebar for simplicity, 
      // but styling matches narrative
      return html.replace(/\[([^\]]+)\]/g, '<span class="text-yellow-500">$1</span>');
  };

  return (
    <div className="w-full md:w-80 bg-neutral-900 border-r border-neutral-800 flex flex-col h-[40vh] md:h-full text-xs md:text-sm font-mono overflow-hidden">

      {/* Files Section */}
      <div className="flex-1 flex flex-col min-h-0 border-b border-neutral-800">
        <div className="p-2 bg-neutral-950 border-b border-neutral-800 flex justify-between items-center text-gray-400 font-bold uppercase tracking-wider text-[10px]">
          <span className="flex items-center gap-1"><FileText size={12} /> World Files</span>
          <div className="flex items-center gap-3">
             <label className="flex items-center gap-1 cursor-pointer hover:text-white transition-colors">
               <input type="checkbox" checked={debugMode} onChange={onToggleDebug} className="hidden" />
               <Settings size={12} className={debugMode ? "text-yellow-400" : ""} />
               <span className={debugMode ? "text-yellow-400" : ""}>DEBUG</span>
             </label>
             <button onClick={onReset} className="hover:text-red-400 transition-colors" title="Reset World">
                <RefreshCw size={12} />
             </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1">
          {files.map(filename => {
            const isExpanded = expandedFile === filename;
            const content = fileSystem.read(filename) || '';
            const displayName = fileSystem.getDisplayName(filename);

            return (
              <div key={filename} className="bg-neutral-800/50 rounded overflow-hidden">
                <div 
                  className={`px-2 py-1.5 cursor-pointer hover:bg-neutral-800 flex items-center gap-2 ${isExpanded ? 'bg-neutral-800' : ''}`}
                  onClick={() => setExpandedFile(isExpanded ? null : filename)}
                >
                   {isExpanded ? <ChevronDown size={12} className="text-gray-500" /> : <ChevronRight size={12} className="text-gray-500" />}
                   <span className="text-blue-400 font-semibold truncate">{displayName}</span>
                </div>
                {isExpanded && (
                  <div className="p-2 border-t border-neutral-700 bg-black text-gray-400 whitespace-pre-wrap text-[10px] md:text-xs leading-relaxed">
                    <span dangerouslySetInnerHTML={{ __html: parseLinks(formatContent(content)) }} />
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Status Section */}
      <div className="h-1/3 min-h-[150px] flex flex-col bg-neutral-950">
        <div className="p-2 border-b border-neutral-800 bg-neutral-900 text-gray-400 font-bold uppercase tracking-wider text-[10px] flex items-center gap-1">
           <Activity size={12} /> System Logs
        </div>
        <div className="flex-1 overflow-y-auto p-2 font-mono text-xs">
           {updates.length === 0 && <span className="text-gray-700 italic">No updates...</span>}
           {updates.map((u, i) => (
             <div key={i} className="mb-1">
               <span className={
                 u.value < 0 ? 'text-red-400' : 
                 u.value > 0 ? 'text-green-400' : 
                 'text-yellow-400'
               }>
                 {u.text}
               </span>
             </div>
           ))}
        </div>
      </div>

    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';

interface InputAreaProps {
  onSend: (text: string) => void;
  disabled: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || disabled) return;
    onSend(input.trim());
    setInput('');
  };

  return (
    <form 
      onSubmit={handleSubmit} 
      className="border-t border-neutral-800 bg-neutral-900 p-2 md:p-4 flex gap-2 sticky bottom-0 z-10"
    >
      <input
        type="text"
        value={input}
        onChange={(e) => setInput(e.target.value)}
        placeholder={disabled ? "Processing..." : "Enter action..."}
        disabled={disabled}
        className="flex-1 bg-black border border-neutral-700 rounded px-4 py-3 text-gray-200 focus:outline-none focus:border-blue-500 font-mono transition-colors disabled:opacity-50"
        autoComplete="off"
      />
      <button 
        type="submit" 
        disabled={disabled || !input.trim()}
        className="bg-blue-600 hover:bg-blue-500 text-white font-bold px-6 py-2 rounded transition-colors disabled:bg-neutral-800 disabled:text-gray-500"
      >
        SEND
      </button>
    </form>
  );
};

export default InputArea;

