  const [gameOver, setGameOver] = useState(false);

  // Sync state with filesystem on mount and updates
  const syncFiles = () => {
    setFiles(fileSystem.list());
    const timeContent = fileSystem.read('WorldTime.txt');
    if (timeContent) setWorldTime(timeContent);
  };

  useEffect(() => {
    syncFiles();
