export class AIEngine {
  private fs: FileSystem;
  private ai: GoogleGenAI;

  constructor(fileSystem: FileSystem) {
    this.fs = fileSystem;
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async initialize(startingPrompt: string): Promise<AIResponse | null> {
    try {
      const prompt = `Initialize world: ${startingPrompt}`;
      return await this.handleRequest(prompt);
    } catch (e) {
      console.error("Initialization failed", e);
      return { narrative: "System initialization failed. Please check API Key." };
    }
  }

  async processAction(action: string): Promise<AIResponse | null> {
    try {
      const files = this.fs.getAll();
      const context = Object.entries(files)
        .map(([name, content]) => `=== ${name} ===\n${content}`)
        .join('\n\n');

      const prompt = `Current files:\n${context}\n\nPlayer action: ${action}\n\nProcess this action. If it requires rolls, return "checks". Otherwise return "narrative" and updates.`;

      return await this.handleRequest(prompt);
    } catch (e) {
      console.error("Processing failed", e);
      return { narrative: "Error processing action." };
    }
  }

  private async handleRequest(userPrompt: string): Promise<AIResponse | null> {
    let responseText = await this.callAI(userPrompt);
    let data: AIResponse;

    try {
      data = JSON.parse(responseText);
    } catch (e) {
      const match = responseText.match(/```json([\s\S]*?)```/);
      if (match) {
        try { data = JSON.parse(match[1]); }
        catch (e2) { return { narrative: "System Error: AI returned invalid JSON." }; }
      } else {
        return { narrative: "System Error: AI returned invalid format." };
      }
    }

    if (data.checks && Array.isArray(data.checks) && data.checks.length > 0) {
      const results = data.checks.map(check => {
        const roll = Math.floor(Math.random() * 1001);
        const outcome = this.determineOutcome(roll, check.thresholds);
        return { name: check.name, description: check.description, outcome: outcome, roll: roll, thresholds: check.thresholds };
      });

      const resultReport = results.map(r => `Check: ${r.name}\nReason: ${r.description}\nRoll: ${r.roll} / 1000\nRESULT: ${r.outcome}`).join('\n\n');
      const followUpPrompt = `PREVIOUS CONTEXT: ${userPrompt}\n\n[SYSTEM: Probability Checks Completed]\n\n${resultReport}\n\nGenerate the narrative based on these results.`;

      responseText = await this.callAI(followUpPrompt);
      try {
        const match = responseText.match(/```json([\s\S]*?)```/);
        data = match ? JSON.parse(match[1]) : JSON.parse(responseText);
      } catch (e) {
        return { narrative: "Error processing check results." };
      }
    }

    this.processResponseData(data);
    return data;
  }

  private determineOutcome(roll: number, thresholds: { [outcome: string]: number }): string {
    const sorted = Object.entries(thresholds).sort(([, valA], [, valB]) => valB - valA);
    for (const [outcome, minVal] of sorted) {
      if (roll >= minVal) return outcome;
    }
    return "Failure";
  }

  private processResponseData(data: AIResponse) {
    if (!data || !data.files) return;
    for (const [filename, fileData] of Object.entries(data.files)) {
      if (typeof fileData === 'string') {
        this.fs.write(filename, fileData);
      } else if (fileData && fileData.content) {
        this.fs.write(filename, fileData.content, fileData.displayName);
      }
    }
  }

  private async callAI(prompt: string): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: 'application/json',
        temperature: 0.7,
      }
    });
    return response.text || "{}";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { AIEngine } from './services/aiEngine';
import { FileSystem } from './services/fileSystem';
import { NarrativeEntry, UpdateItem } from './types';
import Sidebar from './components/Sidebar';
import NarrativeWindow from './components/NarrativeWindow';
import InputArea from './components/InputArea';
import Modal from './components/Modal';

// Instantiate services outside component to persist across re-renders
const fileSystem = new FileSystem();
const aiEngine = new AIEngine(fileSystem);

function App() {
  const [narrative, setNarrative] = useState<NarrativeEntry[]>([]);
  const [files, setFiles] = useState<string[]>([]);
  const [updates, setUpdates] = useState<UpdateItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const [debugMode, setDebugMode] = useState(false);
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [expandedFile, setExpandedFile] = useState<string | null>(null);
  const [worldTime, setWorldTime] = useState<string>('');
  const [gameOver, setGameOver] = useState(false);

  // Sync state with filesystem on mount and updates
  const syncFiles = () => {
    setFiles(fileSystem.list());
    const timeContent = fileSystem.read('WorldTime.txt');
    if (timeContent) setWorldTime(timeContent);
  };

  useEffect(() => {
    syncFiles();
    if (fileSystem.list().length === 0) {
       setNarrative([{
         id: 'init',
         text: 'Welcome to AI-MUD Gemini Edition. Enter a scenario prompt to begin (e.g., "A cyberpunk detective in Neo-Tokyo")',
         type: 'system'
       }]);
    } else {
      setIsInitialized(true);
      setNarrative([{
        id: 'resume',
        text: 'Session Resumed. Systems operational.',
        type: 'system'
      }]);
    }
  }, []);

  const handleAction = async (text: string) => {
    setIsProcessing(true);
    const userActionId = Date.now().toString();
    setNarrative(prev => [...prev, { id: userActionId, text: text, type: 'user' }]);

    let result;
    if (!isInitialized) {
       result = await aiEngine.initialize(text);
       setIsInitialized(true);
    } else {
       result = await aiEngine.processAction(text);
    }

    if (result) {
      if (result.narrative) {
        setNarrative(prev => [...prev, { id: Date.now().toString() + 'ai', text: result.narrative, type: 'ai' }]);
      }
      if (result.updates) {
        setUpdates(prev => [...result.updates!, ...prev].slice(0, 50));
      }
      if (result.gameOver) {
        setGameOver(true);
        setNarrative(prev => [...prev, { id: 'death', text: 'CRITICAL FAILURE: Vital signs zero. Simulation Terminated.', type: 'system' }]);
      }
      syncFiles();
    }
    setIsProcessing(false);
  };

  const handleReferenceClick = (ref: string) => {
    const filename = fileSystem.findFileByReference(ref);
    if (filename) {
      setExpandedFile(filename);
    } else {
      // Provide user feedback that the file was not found
      setNarrative(prev => [...prev, { 
        id: Date.now().toString() + 'err', 
        text: `Error: Reference "${ref}" not found in current world files.`, 
        type: 'system' 
      }]);
    }
  };

  const handleReset = () => {
    fileSystem.clear();
    setNarrative([{ id: 'reset', text: 'System Reset Complete. Enter a new scenario.', type: 'system' }]);
    setUpdates([]);
    setGameOver(false);
    setIsInitialized(false);
    setExpandedFile(null);
    syncFiles();
    setIsResetModalOpen(false);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen w-full bg-black text-gray-200 overflow-hidden">
      <Sidebar 
        files={files}
        fileSystem={fileSystem}
        updates={updates}
        debugMode={debugMode}
        onToggleDebug={() => setDebugMode(!debugMode)}
        onReset={() => setIsResetModalOpen(true)}
        expandedFile={expandedFile}
        setExpandedFile={setExpandedFile}
      />

      <div className="flex-1 flex flex-col min-w-0 min-h-0 relative">
        <div className="bg-neutral-900 border-b border-neutral-800 p-2 text-center text-xs text-blue-400 font-mono tracking-widest shadow-lg z-10">
           {worldTime || "TIME: UNKNOWN"}
        </div>

        <NarrativeWindow 
          history={narrative}
          onReferenceClick={handleReferenceClick}
          debugMode={debugMode}
          fileSystem={fileSystem}
        />

        {gameOver && (
          <div className="absolute inset-0 flex items-center justify-center bg-red-900/20 backdrop-blur-sm z-20 pointer-events-none">
             <div className="bg-black border-2 border-red-600 p-8 rounded text-center shadow-[0_0_50px_rgba(220,38,38,0.5)]">
               <h1 className="text-4xl font-bold text-red-600 mb-2">TERMINATED</h1>
               <p className="text-gray-400">Please reset the system to restart.</p>
             </div>
          </div>
        )}

        <InputArea onSend={handleAction} disabled={isProcessing || gameOver} />
      </div>

      <Modal 
        isOpen={isResetModalOpen}
        onConfirm={handleReset}
        onCancel={() => setIsResetModalOpen(false)}
      />
    </div>
  );
}

export default App;

import React, { useEffect, useRef } from 'react';
import { UpdateItem } from '../types';
import { FileSystem } from '../services/fileSystem';
import { FileText, ChevronRight, ChevronDown, Activity, Settings, RefreshCw } from 'lucide-react';

interface SidebarProps {
  files: string[];
  fileSystem: FileSystem;
  updates: UpdateItem[];
  debugMode: boolean;
  onToggleDebug: () => void;
  onReset: () => void;
  expandedFile: string | null;
  setExpandedFile: (filename: string | null) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  files, 
  fileSystem, 
  updates, 
  debugMode, 
  onToggleDebug, 
  onReset,
  expandedFile,
  setExpandedFile
}) => {
  const expandedRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (expandedFile && expandedRef.current) {
      expandedRef.current.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }, [expandedFile]);

  const formatContent = (content: string) => {
    if (!content) return '<span class="text-gray-700 italic">This file is empty.</span>';
    if (debugMode) {
      return content.replace(/hide\[(.*?)\]/gs, '<span class="text-yellow-300 bg-yellow-900/20 px-1 border border-dashed border-yellow-800 rounded">$1</span>');
    }
    return content.replace(/hide\[.*?\]/gs, '<span class="text-gray-600 italic font-mono">[hidden]</span>');
  };

  const parseLinks = (html: string) => {
      return html.replace(/\[([^\]]+)\]/g, '<span class="text-yellow-500">$1</span>');
  };

  return (
    <div className="w-full md:w-80 bg-neutral-900 border-r border-neutral-800 flex flex-col h-[40vh] md:h-full text-xs md:text-sm font-mono overflow-hidden">
      <div className="flex-1 flex flex-col min-h-0 border-b border-neutral-800">
        <div className="p-2 bg-neutral-950 border-b border-neutral-800 flex justify-between items-center text-gray-400 font-bold uppercase tracking-wider text-[10px]">
          <span className="flex items-center gap-1"><FileText size={12} /> World Files</span>
          <div className="flex items-center gap-3">
             <label className="flex items-center gap-1 cursor-pointer hover:text-white transition-colors">
               <input type="checkbox" checked={debugMode} onChange={onToggleDebug} className="hidden" />
               <Settings size={12} className={debugMode ? "text-yellow-400" : ""} />
               <span className={debugMode ? "text-yellow-400" : ""}>DEBUG</span>
             </label>
             <button onClick={onReset} className="hover:text-red-400 transition-colors" title="Reset World">
                <RefreshCw size={12} />
             </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1">
          {files.map(filename => {
            const isExpanded = expandedFile === filename;
            const content = fileSystem.read(filename) || '';
            const displayName = fileSystem.getDisplayName(filename);

            return (
              <div key={filename} className="bg-neutral-800/50 rounded overflow-hidden" ref={isExpanded ? expandedRef : null}>
                <div 
                  className={`px-2 py-1.5 cursor-pointer hover:bg-neutral-800 flex items-center gap-2 ${isExpanded ? 'bg-neutral-800' : ''}`}
                  onClick={() => setExpandedFile(isExpanded ? null : filename)}
                >
                   {isExpanded ? <ChevronDown size={12} className="text-gray-500" /> : <ChevronRight size={12} className="text-gray-500" />}
                   <span className="text-blue-400 font-semibold truncate">{displayName}</span>
                </div>
                {isExpanded && (
                  <div className="p-2 border-t border-neutral-700 bg-black text-gray-400 whitespace-pre-wrap text-[10px] md:text-xs leading-relaxed">
                    <span dangerouslySetInnerHTML={{ __html: parseLinks(formatContent(content)) }} />
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      <div className="h-1/3 min-h-[150px] flex flex-col bg-neutral-950">
        <div className="p-2 border-b border-neutral-800 bg-neutral-900 text-gray-400 font-bold uppercase tracking-wider text-[10px] flex items-center gap-1">
           <Activity size={12} /> System Logs
        </div>
        <div className="flex-1 overflow-y-auto p-2 font-mono text-xs">
           {updates.length === 0 && <span className="text-gray-700 italic">No updates...</span>}
           {updates.map((u, i) => (
             <div key={i} className="mb-1">
               <span className={u.value < 0 ? 'text-red-400' : u.value > 0 ? 'text-green-400' : 'text-yellow-400'}>
                 {u.text}
               </span>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
